  .container {
    width: 90%;
  }
}

@media (max-width: 550px) {
  .container {
    width: 85%;
    h1 {
      font-size: 4rem;
    }
  }
}

@media (max-width: 380px) {
  .container {
    h1 {
      font-size: 3.3rem;
    }
    p {
      font-size: 1.5rem;
    }
  }
}

@media (max-width: 360px) {
  .container h1 {
    font-size: 3rem;
  }
  .line {
    margin-top: 3rem;
  }
  .p-email {
    margin-bottom: 1rem;
  }
}

@media (max-height: 740px) {
  .container-center {
    height: 60%;
  }
}

@media (max-height: 600px) {
  .container-center {
    height: 70%;
  }
}

