sources.scss/sections/_hero.scss:
// Hero section
h1 {
  font-weight: 600;
  font-size: 6rem;
  line-height: 6rem;
}

.hero__container {
  display: flex;
  justify-content: space-between;
  align-items: center;
}

.hero__text-wrapper {
  display: flex;
  flex-direction: column;
  gap: $hero-gap;
}

.hero__copy {
  width: 42rem;
  line-height: 1.5;

  p {
    font-size: 1.9rem;
    line-height: 3.5rem;
    letter-spacing: 0.7;
  }
}

.hero__cta-buttons {
  margin: 10px 0;
}

@keyframes updown {
  0% {
    transform: translateY(0);
  }

  100% {
    transform: translateY(1rem);
  }
}

.chevron-container {
  display: block;
  text-align: center;
  animation: updown infinite alternate 1.5s ease-in-out;

  i {
    font-size: 15px;
  }
}

.hero__img {
  width: 35rem;
}

.img--round {
  border-radius: 50%;
}

@media (max-width: 1000px) {
